import React, { createContext, useState, useContext, useEffect } from 'react';
import { supabase } from '../utils/supabaseClient';

const AuthContext = createContext();

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [session, setSession] = useState(null);

  // Lightweight, non-blocking profile fetcher
  const fetchUserProfile = async (userId) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();
      if (error) {
        if (error.code === 'PGRST116') {
          setProfile(null);
          return null;
        }
        throw error;
      }
      setProfile(data);
      return data;
    } catch (error) {
      setProfile(null);
      return null;
    }
  };

  // Check and refresh session
  const refreshSession = async () => {
    try {
      console.log('🔄 Checking/refreshing session...');
      const { data: { session: currentSession }, error } = await supabase.auth.getSession();
      
      if (error) {
        console.error('❌ Session check error:', error);
        throw error;
      }

      console.log('🔍 Current session:', currentSession ? 'Valid' : 'Invalid');
      
      if (currentSession?.user) {
        setSession(currentSession);
        setUser(currentSession.user);
        // Fetch profile in background to avoid blocking UI
        fetchUserProfile(currentSession.user.id);
      } else {
        setSession(null);
        setUser(null);
        setProfile(null);
      }
      
      return currentSession;
    } catch (error) {
      console.error('❌ Session refresh failed:', error);
      setSession(null);
      setUser(null);
      setProfile(null);
      return null;
    }
  };

  // Enhanced logout function with error handling
  const logout = async () => {
    try {
      console.log('🚪 Attempting logout...');
      
      // Clear local state first
      setUser(null);
      setProfile(null);
      setSession(null);
      
      // Try to sign out from Supabase with error handling
      const { error } = await supabase.auth.signOut();
      
      if (error) {
        // If it's a session missing error, it might already be logged out
        if (error.message.includes('AuthSessionMissingError') || 
            error.message.includes('session missing')) {
          console.log('ℹ️ Session already invalidated, continuing with local logout');
          return { success: true };
        }
        throw error;
      }
      
      console.log('✅ Logout successful');
      return { success: true };
    } catch (error) {
      console.error('❌ Logout error:', error);
      
      // Even if Supabase logout fails, ensure local state is cleared
      setUser(null);
      setProfile(null);
      setSession(null);
      
      // Clear any residual tokens/local storage
      localStorage.removeItem('supabase.auth.token');
      sessionStorage.removeItem('supabase.auth.token');
      
      return { 
        success: false, 
        error: error.message,
        localCleared: true // Indicate local state was cleared anyway
      };
    }
  };

  // Enhanced auth state listener
  useEffect(() => {
    const initializeAuth = async () => {
      try {
        setLoading(true);
        console.log('🚀 Initializing auth...');
        // On cold start, ensure we don't show a stale user from a previous run
        // If Supabase has no valid session, clear any locally cached state/tokens
        const { data: { session: bootSession } } = await supabase.auth.getSession();
        if (!bootSession) {
          setSession(null);
          setUser(null);
          setProfile(null);
          localStorage.removeItem('supabase.auth.token');
          sessionStorage.removeItem('supabase.auth.token');
          // Do not block — we can finish initialization now
          setLoading(false);
        } else {
          // Fast path: set user/session immediately so UI can render
          setSession(bootSession);
          setUser(bootSession.user);
          setLoading(false);

          // Fetch profile in background (non-blocking)
          fetchUserProfile(bootSession.user.id).catch(() => {});
        }
      } catch (error) {
        console.error('❌ Auth initialization error:', error);
        setUser(null);
        setProfile(null);
        setSession(null);
        setLoading(false);
      }
    };

    initializeAuth();

    // Enhanced auth state change listener with session refresh
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (event, currentSession) => {
        console.log('🔐 Auth state change:', event, currentSession ? 'Has session' : 'No session');

        switch (event) {
          case 'SIGNED_IN':
          case 'TOKEN_REFRESHED':
          case 'USER_UPDATED':
            if (currentSession?.user) {
              setSession(currentSession);
              setUser(currentSession.user);
              // Non-blocking
              fetchUserProfile(currentSession.user.id);
            }
            break;

          case 'SIGNED_OUT':
            console.log('✅ Signed out event received');
            setSession(null);
            setUser(null);
            setProfile(null);
            break;

          case 'USER_DELETED':
            setSession(null);
            setUser(null);
            setProfile(null);
            break;

          case 'INITIAL_SESSION':
            if (currentSession?.user) {
              setSession(currentSession);
              setUser(currentSession.user);
              // Non-blocking
              fetchUserProfile(currentSession.user.id).catch(() => {});
            }
            break;
        }

        setLoading(false);
      }
    );

    // Set up periodic session check (every 5 minutes)
    const sessionCheckInterval = setInterval(() => {
      refreshSession();
    }, 5 * 60 * 1000);

    return () => {
      subscription.unsubscribe();
      clearInterval(sessionCheckInterval);
    };
  }, []);

  // Enhanced login with session validation
  const login = async (email, password) => {
    try {
      console.log('🔐 Attempting login...');
      const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      if (error) throw error;
      
      console.log('✅ Login successful, validating session...');
      await refreshSession();
      
      return { success: true, user: data.user };
    } catch (error) {
      console.error('❌ Login failed:', error);
      return { success: false, error: error.message };
    }
  };

  const register = async (userData) => {
    try {
      const { data, error } = await supabase.auth.signUp({
        email: userData.email,
        password: userData.password,
        options: {
          data: {
            first_name: userData.firstName,
            last_name: userData.lastName,
            user_type: userData.userType,
          },
        },
      });

      if (error) throw error;

      // Create profile after successful registration
      if (data.user) {
        await supabase
          .from('profiles')
          .insert([
            {
              id: data.user.id,
              email: data.user.email,
              first_name: userData.firstName,
              last_name: userData.lastName,
              user_type: userData.userType,
              created_at: new Date().toISOString(),
            }
          ]);
      }

      return { 
        success: true, 
        user: data.user,
        needsEmailVerification: !data.session
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  };

  const loginWithGoogle = async (userType = 'customer') => {
    try {
      // ✅ Sanitize the origin to prevent malformed URLs (fixes "lochttps" bug)
      let origin = window.location.origin;
  
      // Fix any common malformed cases (like "lochttps" or "vercel.appalhost")
      origin = origin.replace('lochttps', 'https').replace('httphttp', 'http').replace('httpshttps', 'https');
      origin = origin.replace('vercel.appalhost', 'vercel.app'); // Just in case the domain got merged
  
      const redirectTo = `${origin}/oauth-success`;
  
      const { data, error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: { redirectTo },
      });
  
      if (error) throw error;
      return { success: true };
    } catch (error) {
      console.error('❌ Google login error:', error);
      return { success: false, error: error.message };
    }
  };
  

  // Session validation function for other components to use
  const validateSession = async () => {
    return await refreshSession();
  };

  const value = {
    user,
    profile,
    session,
    userData: user ? { ...user, profile } : null,
    isAuthenticated: !!user && !!session,
    userType: profile?.user_type || 'customer',
    login,
    register,
    loginWithGoogle,
    logout, // Enhanced logout function
    loading,
    refreshProfile: () => user && fetchUserProfile(user.id),
    validateSession,
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
}